/**
 * Nemotron VoiceChat Client for the browser.
 *
 * Mirrors the protocol used by nemotron-voicechat-client.py:
 *   - Connects via WebSocket to /v1/frontend_realtime
 *   - Captures microphone audio at 24 kHz mono
 *   - Encodes audio with Opus in OGG container (via opusscript) — same as sphn
 *   - Sends 80 ms chunks as base64 JSON messages with encoding: "opus"
 *   - Receives text transcription deltas and completed transcripts
 *   - Decodes received OGG Opus audio with opusscript and plays via Web Audio
 */

import { OggOpusReader, OggOpusWriter, preloadOpusWasm } from './ogg-opus-writer'

// ── Audio configuration (matches Python client exactly) ──────────────────────
const INPUT_SAMPLE_RATE = 24000
const OUTPUT_SAMPLE_RATE = 24000
const CHANNELS = 1
const INPUT_CHUNK_DURATION_MS = 80
// @ts-expect-error unused
const INPUT_CHUNK_SIZE = (INPUT_SAMPLE_RATE * INPUT_CHUNK_DURATION_MS) / 1000 // 1920 samples

// ── Event types emitted by the client ────────────────────────────────────────
export type ClientEvent =
	| { type: 'status'; message: string }
	| { type: 'queue-position'; position: number }
	| { type: 'session-created'; sessionId: string }
	| { type: 'user-transcript-delta'; text: string }
	| { type: 'user-transcript-done'; text: string }
	| { type: 'agent-text-delta'; text: string }
	| { type: 'agent-text-done'; text: string }
	| { type: 'error'; message: string }

export type EventCallback = (event: ClientEvent) => void

export interface ClientOptions {
	serverAddress: string
	apiKey?: string
	functionId?: string
	projectId?: string
	model?: string
	onEvent: EventCallback
}

// ── Client class ─────────────────────────────────────────────────────────────
export class NemotronVoicechatClient {
	private ws: WebSocket | null = null
	private audioContext: AudioContext | null = null
	private mediaStream: MediaStream | null = null
	private workletNode: AudioWorkletNode | null = null
	private sourceNode: MediaStreamAudioSourceNode | null = null
	private gainNode: GainNode | null = null

	// Opus encoder (OGG Opus, matching sphn)
	private oggWriter: OggOpusWriter | null = null

	// Opus decoder + playback (ring buffer via AudioWorklet)
	private oggReader: OggOpusReader | null = null
	private playbackCtx: AudioContext | null = null
	private playbackWorklet: AudioWorkletNode | null = null

	// State
	private _connected = false
	private _recording = false
	private chunksSent = 0

	private options: ClientOptions

	constructor(options: ClientOptions) {
		this.options = options
	}

	get isConnected(): boolean {
		return this._connected
	}
	get isRecording(): boolean {
		return this._recording
	}

	// ── Connection ──────────────────────────────────────────────────────────

	/**
	 * Two-step authenticated connection:
	 * 1. POST /v1/realtime/auth_token to get an ephemeral single-use token
	 * 2. Open WebSocket with ?model=...&token=... query params
	 */
	async connect(): Promise<void> {
		this.emit({ type: 'status', message: 'Authenticating...' })

		// Pre-fetch the WASM binary before opening the WebSocket so that
		// OggOpusReader/OggOpusWriter constructors (called synchronously in
		// ws.onopen / startRecording) have the binary ready.
		await preloadOpusWasm()

		const token = await this.fetchAuthToken()

		const uri = this.buildWsUri(token)
		this.emit({ type: 'status', message: `Connecting to ${uri}...` })

		return new Promise<void>((resolve, reject) => {
			try {
				this.ws = new WebSocket(uri)
			} catch (e) {
				reject(e)
				return
			}

			this.ws.onopen = () => {
				this._connected = true
				this.oggReader = new OggOpusReader(OUTPUT_SAMPLE_RATE, CHANNELS)
				this.emit({ type: 'status', message: 'Connected' })
				resolve()
			}

			this.ws.onmessage = evt => this.handleMessage(evt.data as string)

			this.ws.onerror = () => {
				this.emit({ type: 'error', message: 'WebSocket connection error' })
				if (!this._connected) reject(new Error('Connection failed'))
			}

			this.ws.onclose = () => {
				const wasConnected = this._connected
				this._connected = false
				this.stopRecording()
				if (wasConnected) {
					this.emit({ type: 'status', message: 'Disconnected' })
				}
			}
		})
	}

	disconnect(): void {
		this.stopRecording()
		if (this.ws) {
			this.ws.close()
			this.ws = null
		}
		if (this.oggReader) {
			this.oggReader.destroy()
			this.oggReader = null
		}
		if (this.playbackWorklet) {
			this.playbackWorklet.disconnect()
			this.playbackWorklet = null
		}
		if (this.playbackCtx) {
			this.playbackCtx.close().catch(() => {})
			this.playbackCtx = null
		}
		this._connected = false
	}

	// ── Microphone recording ────────────────────────────────────────────────

	async startRecording(): Promise<void> {
		if (!this._connected) throw new Error('Not connected')
		if (this._recording) return

		// Create playback AudioContext + worklet here (inside user gesture) so
		// browsers won't block it due to autoplay policy.
		if (!this.playbackCtx) {
			this.playbackCtx = new AudioContext({ sampleRate: OUTPUT_SAMPLE_RATE })
			await this.playbackCtx.audioWorklet.addModule(
				'/playback-worklet-processor.js'
			)
			this.playbackWorklet = new AudioWorkletNode(
				this.playbackCtx,
				'playback-processor'
			)
			this.playbackWorklet.connect(this.playbackCtx.destination)
		}
		if (this.playbackCtx.state === 'suspended') {
			await this.playbackCtx.resume()
		}

		// Create OGG Opus encoder (matches sphn.OpusStreamWriter)
		this.oggWriter = new OggOpusWriter(INPUT_SAMPLE_RATE, CHANNELS)

		// Request microphone
		this.mediaStream = await navigator.mediaDevices.getUserMedia({
			audio: {
				sampleRate: INPUT_SAMPLE_RATE,
				channelCount: CHANNELS,
				echoCancellation: true,
				noiseSuppression: true,
			},
		})

		// AudioContext at 24 kHz — resamples mic input automatically
		this.audioContext = new AudioContext({ sampleRate: INPUT_SAMPLE_RATE })

		// Load AudioWorklet processor
		await this.audioContext.audioWorklet.addModule('/audio-worklet-processor.js')

		// Wire: mic → worklet → zero-gain → destination
		this.sourceNode = this.audioContext.createMediaStreamSource(this.mediaStream)
		this.workletNode = new AudioWorkletNode(
			this.audioContext,
			'capture-processor'
		)

		this.workletNode.port.onmessage = (evt: MessageEvent<Float32Array>) => {
			this.sendAudioChunk(evt.data)
		}

		this.gainNode = this.audioContext.createGain()
		this.gainNode.gain.value = 0
		this.sourceNode.connect(this.workletNode)
		this.workletNode.connect(this.gainNode)
		this.gainNode.connect(this.audioContext.destination)

		this._recording = true
		this.chunksSent = 0
		this.emit({ type: 'status', message: 'Recording' })
	}

	stopRecording(): void {
		if (!this._recording) return

		this.workletNode?.disconnect()
		this.workletNode = null
		this.sourceNode?.disconnect()
		this.sourceNode = null
		this.gainNode?.disconnect()
		this.gainNode = null

		this.mediaStream?.getTracks().forEach(t => t.stop())
		this.mediaStream = null

		if (this.audioContext) {
			this.audioContext.close().catch(() => {})
			this.audioContext = null
		}

		if (this.oggWriter) {
			this.oggWriter.destroy()
			this.oggWriter = null
		}

		this._recording = false
		this.emit({
			type: 'status',
			message: this._connected ? 'Connected' : 'Disconnected',
		})
	}

	// ── Auth & URI helpers ──────────────────────────────────────────────────

	private async fetchAuthToken(): Promise<string> {
		const baseUrl = this.getHttpBaseUrl(this.options.serverAddress)

		const headers: Record<string, string> = {
			'Content-Type': 'application/json',
		}
		if (this.options.apiKey) {
			headers['Authorization'] = `Bearer ${this.options.apiKey}`
		}
		if (this.options.projectId) {
			headers['Crusoe-Project-Id'] = this.options.projectId
		}
		headers['X-CSRF-Token'] = 'voice-chat'

		const resp = await fetch(`${baseUrl}/v1/realtime/auth_token`, {
			method: 'POST',
			headers,
			credentials: 'include',
		})

		if (!resp.ok) {
			const body = await resp.text().catch(() => '')
			throw new Error(`Auth token request failed (${resp.status}): ${body}`)
		}

		const data = await resp.json()
		return data.token as string
	}

	private buildWsUri(token: string): string {
		let address = this.options.serverAddress
		if (!address.startsWith('wss://') && !address.startsWith('ws://')) {
			if (!address.includes(':')) {
				throw new Error(
					"Server must include port (e.g. 'localhost:9000') or use full URI"
				)
			}
			address = `wss://${address}`
		}

		const url = new URL(address)
		url.searchParams.set('token', token)
		if (this.options.model) {
			url.searchParams.set('model', this.options.model)
		}
		return url.toString()
	}

	private getHttpBaseUrl(address: string): string {
		if (!address.includes('://')) {
			return `https://${address}`
		}
		const url = new URL(address)
		const protocol =
			url.protocol === 'wss:'
				? 'https:'
				: url.protocol === 'ws:'
				? 'http:'
				: url.protocol
		return `${protocol}//${url.host}`
	}

	// ── Sending audio ───────────────────────────────────────────────────────

	/**
	 * Encode a 80 ms PCM float32 chunk with Opus in OGG container and send
	 * over the WebSocket. This mirrors the Python client exactly:
	 *
	 *   opus_writer.append_pcm(audio_float32)
	 *   opus_data = opus_writer.read_bytes()
	 *   audio_base64 = base64.b64encode(opus_data)
	 */
	private sendAudioChunk(samples: Float32Array): void {
		if (!this.ws || this.ws.readyState !== WebSocket.OPEN) return
		if (!this.oggWriter) return

		// Encode float32 PCM → OGG Opus bytes (same format as sphn)
		const oggBytes = this.oggWriter.encode(samples)

		if (oggBytes.length === 0) return

		const base64 = arrayBufferToBase64(oggBytes)

		const message = {
			type: 'input_audio_buffer.append',
			event_id: crypto.randomUUID(),
			audio: base64,
			encoding: 'opus',
			sample_rate: INPUT_SAMPLE_RATE,
			channels: CHANNELS,
		}

		this.ws.send(JSON.stringify(message))
		this.chunksSent++
	}

	// ── Receiving messages ──────────────────────────────────────────────────

	private handleMessage(raw: string): void {
		let data: Record<string, unknown>
		try {
			data = JSON.parse(raw)
		} catch {
			this.emit({ type: 'error', message: 'Failed to parse server message' })
			return
		}

		const msgType = (data.type as string) || 'unknown'

		switch (msgType) {
			case 'session.created': {
				const session = data.session as Record<string, unknown> | undefined
				this.emit({
					type: 'session-created',
					sessionId: (session?.id as string) ?? 'unknown',
				})
				break
			}

			case 'response.output_audio.delta': {
				if (data.delta) {
					const opusBytes = base64ToUint8Array(data.delta as string)
					this.playAudioDelta(opusBytes)
				}
				break
			}

			case 'response.output_text.delta':
				if (data.delta) {
					this.emit({ type: 'agent-text-delta', text: data.delta as string })
				}
				break

			case 'conversation.item.input_audio_transcription.delta':
				if (data.delta) {
					this.emit({
						type: 'user-transcript-delta',
						text: data.delta as string,
					})
				}
				break

			case 'conversation.item.input_audio_transcription.completed':
				this.emit({
					type: 'user-transcript-done',
					text: (data.transcript as string) ?? '',
				})
				break

			case 'response.output_text.done':
				this.emit({
					type: 'agent-text-done',
					text: (data.text as string) ?? '',
				})
				break

			case 'error': {
				const err = data.error as Record<string, unknown> | undefined
				const errMsg = (err?.message as string) ?? 'Unknown error'
				const errCode = (err?.code as string) ?? 'unknown'
				this.emit({ type: 'error', message: `${errCode}: ${errMsg}` })
				break
			}

			case 'queue_position': {
				const position = data.position as number
				if (typeof position === 'number') {
					this.emit({ type: 'queue-position', position })
				}
				break
			}

			case 'session.updated':
				break

			default:
				break
		}
	}

	// ── Audio playback ───────────────────────────────────────────────────────

	/**
	 * Decode incoming OGG Opus audio with opusscript and push PCM samples
	 * into the playback worklet's ring buffer. This mirrors the Python
	 * client's callback-based playback (ring buffer + constant pull rate).
	 */
	private playAudioDelta(oggData: Uint8Array): void {
		if (!this.oggReader || !this.playbackWorklet) return

		if (this.playbackCtx?.state === 'suspended') {
			this.playbackCtx.resume()
		}

		// Decode OGG Opus → PCM float32 chunks
		const pcmChunks = this.oggReader.decode(oggData)

		// Push decoded audio into the worklet's ring buffer
		for (const chunk of pcmChunks) {
			if (chunk.length > 0) {
				this.playbackWorklet.port.postMessage(chunk)
			}
		}
	}

	// ── Helpers ─────────────────────────────────────────────────────────────

	private emit(event: ClientEvent): void {
		this.options.onEvent(event)
	}
}

// ── Base64 utilities ─────────────────────────────────────────────────────────

function arrayBufferToBase64(bytes: Uint8Array): string {
	let binary = ''
	const CHUNK = 8192
	for (let i = 0; i < bytes.length; i += CHUNK) {
		const slice = bytes.subarray(i, Math.min(i + CHUNK, bytes.length))
		binary += String.fromCharCode(...slice)
	}
	return btoa(binary)
}

function base64ToUint8Array(b64: string): Uint8Array {
	const binary = atob(b64)
	const bytes = new Uint8Array(binary.length)
	for (let i = 0; i < binary.length; i++) {
		bytes[i] = binary.charCodeAt(i)
	}
	return bytes
}
