/**
 * OGG Opus stream writer.
 *
 * Uses opusscript for raw Opus encoding and wraps the frames in OGG pages,
 * producing the same wire format as Python's `sphn.OpusStreamWriter`:
 *
 *   call 1  →  OggS BOS page (OpusHead)
 *   call 2  →  OggS page (OpusTags) + OggS data page(s)
 *   call N  →  OggS data page(s)
 *
 * Each data page contains one or more 20 ms Opus frames.
 */

import { Buffer } from 'buffer'
import OpusScript from 'opusscript'

// ── WASM preloader ─────────────────────────────────────────────────────────
// Emscripten's sync binary fetch (XHR with responseType="arraybuffer") does
// not work in the browser main thread.  We pre-fetch the WASM binary
// asynchronously and pass it to OpusScript via the `wasmBinary` option so the
// Emscripten module skips the broken sync-fetch path entirely.
let _wasmBinary: ArrayBuffer | null = null

export async function preloadOpusWasm(): Promise<void> {
	if (_wasmBinary) return
	const resp = await fetch('/opusscript_native_wasm.wasm')
	if (!resp.ok) throw new Error(`Failed to fetch opusscript WASM: ${resp.status}`)
	_wasmBinary = await resp.arrayBuffer()
}

// ── OGG CRC-32 (polynomial 0x04C11DB7) ──────────────────────────────────────

const CRC_TABLE = new Uint32Array(256)
{
	for (let i = 0; i < 256; i++) {
		let crc = i << 24
		for (let j = 0; j < 8; j++) {
			crc = crc & 0x80000000 ? ((crc << 1) ^ 0x04c11db7) >>> 0 : (crc << 1) >>> 0
		}
		CRC_TABLE[i] = crc >>> 0
	}
}

function oggCrc32(data: Uint8Array, crc = 0): number {
	for (let i = 0; i < data.length; i++) {
		crc = ((crc << 8) ^ CRC_TABLE[((crc >>> 24) ^ data[i]) & 0xff]) >>> 0
	}
	return crc >>> 0
}

// ── Little-endian helpers ────────────────────────────────────────────────────

function writeU32LE(buf: Uint8Array, offset: number, value: number) {
	buf[offset] = value & 0xff
	buf[offset + 1] = (value >>> 8) & 0xff
	buf[offset + 2] = (value >>> 16) & 0xff
	buf[offset + 3] = (value >>> 24) & 0xff
}

function writeU16LE(buf: Uint8Array, offset: number, value: number) {
	buf[offset] = value & 0xff
	buf[offset + 1] = (value >>> 8) & 0xff
}

/**
 * Write a 64-bit granule position as two 32-bit LE words.
 * OGG granule positions can exceed 32 bits but for typical voice chat
 * sessions (< 24 h at 48 kHz) the high word stays 0.
 */
function writeGranuleLE(buf: Uint8Array, offset: number, lo: number, hi = 0) {
	writeU32LE(buf, offset, lo)
	writeU32LE(buf, offset + 4, hi)
}

// ── OGG page builder ─────────────────────────────────────────────────────────

const OGG_CAPTURE = new Uint8Array([0x4f, 0x67, 0x67, 0x53]) // "OggS"

interface OggPageOptions {
	headerType: number // 0x00 normal, 0x02 BOS, 0x04 EOS
	granulePos: number
	serialNo: number
	pageSeq: number
	payload: Uint8Array
}

function buildOggPage(opts: OggPageOptions): Uint8Array {
	const { headerType, granulePos, serialNo, pageSeq, payload } = opts

	// Segment table: each segment ≤ 255 bytes. A 255-byte segment means
	// "continued in next segment". The final segment is < 255.
	const segments: number[] = []
	let remaining = payload.length
	while (remaining >= 255) {
		segments.push(255)
		remaining -= 255
	}
	segments.push(remaining) // final segment (0 is valid — signals exact 255-multiple)

	const headerSize = 27 + segments.length
	const page = new Uint8Array(headerSize + payload.length)

	// Capture pattern
	page.set(OGG_CAPTURE, 0)
	// Version
	page[4] = 0
	// Header type
	page[5] = headerType
	// Granule position (8 bytes LE)
	writeGranuleLE(page, 6, granulePos)
	// Serial number
	writeU32LE(page, 14, serialNo)
	// Page sequence number
	writeU32LE(page, 18, pageSeq)
	// CRC (set to 0 for now, computed below)
	writeU32LE(page, 22, 0)
	// Number of segments
	page[26] = segments.length
	// Segment table
	for (let i = 0; i < segments.length; i++) {
		page[27 + i] = segments[i]
	}
	// Payload
	page.set(payload, headerSize)

	// Compute CRC over the entire page (with CRC field zeroed)
	const crc = oggCrc32(page)
	writeU32LE(page, 22, crc)

	return page
}

// ── OpusHead / OpusTags ──────────────────────────────────────────────────────

function buildOpusHead(
	channels: number,
	sampleRate: number,
	preSkip = 0
): Uint8Array {
	// https://www.rfc-editor.org/rfc/rfc7845.html#section-5.1
	const buf = new Uint8Array(19)
	// "OpusHead"
	buf.set([0x4f, 0x70, 0x75, 0x73, 0x48, 0x65, 0x61, 0x64], 0)
	buf[8] = 1 // version
	buf[9] = channels
	writeU16LE(buf, 10, preSkip)
	writeU32LE(buf, 12, sampleRate)
	writeU16LE(buf, 16, 0) // output gain
	buf[18] = 0 // channel mapping family
	return buf
}

function buildOpusTags(): Uint8Array {
	// https://www.rfc-editor.org/rfc/rfc7845.html#section-5.2
	const vendor = 'opusscript'
	const vendorBytes = new TextEncoder().encode(vendor)
	const buf = new Uint8Array(8 + 4 + vendorBytes.length + 4)
	// "OpusTags"
	buf.set([0x4f, 0x70, 0x75, 0x73, 0x54, 0x61, 0x67, 0x73], 0)
	writeU32LE(buf, 8, vendorBytes.length)
	buf.set(vendorBytes, 12)
	writeU32LE(buf, 12 + vendorBytes.length, 0) // 0 user comments
	return buf
}

// ── Public API ───────────────────────────────────────────────────────────────

// Use 80 ms Opus frames (1920 samples at 24 kHz).
// This matches sphn exactly: each 80 ms chunk becomes a single Opus packet
// (internally a code-3 multi-frame packet with 2×40 ms frames).
const OPUS_FRAME_MS = 80

export class OggOpusWriter {
	private encoder: InstanceType<typeof OpusScript>
	private sampleRate: number
	private channels: number
	private frameSamples: number // samples per Opus frame
	private serialNo: number
	private pageSeq = 0
	private granulePos = 0
	private headerSent = false
	private tagsSent = false

	constructor(sampleRate: number, channels = 1) {
		this.sampleRate = sampleRate
		this.channels = channels
		this.frameSamples = (sampleRate * OPUS_FRAME_MS) / 1000 // 1920 at 24 kHz
		this.serialNo = (Math.random() * 0x7fffffff) >>> 0

		this.encoder = new OpusScript(
			sampleRate as 8000 | 12000 | 16000 | 24000 | 48000,
			channels,
			OpusScript.Application.VOIP,
			// Pass the pre-fetched WASM binary so Emscripten skips its broken
			// sync XHR path.  The `wasmBinary` key is accepted by our patched
			// opusscript (see patches/opusscript+0.1.1.patch).
			(_wasmBinary ? { wasm: true, wasmBinary: _wasmBinary } : { wasm: false }) as any,
		)
	}

	/**
	 * Encode a chunk of PCM float32 samples and return OGG Opus bytes.
	 *
	 * Matches the behaviour of `sphn.OpusStreamWriter`:
	 *   - First call returns the BOS (OpusHead) page.
	 *   - Second call returns the OpusTags page + first data page.
	 *   - Subsequent calls return data pages.
	 *
	 * @param pcmFloat32 Mono float32 samples in [-1, 1]. Length should be
	 *   1920 samples (80 ms at 24 kHz) — matching the Python client's chunk size.
	 */
	encode(pcmFloat32: Float32Array): Uint8Array {
		const pages: Uint8Array[] = []

		// ── Header pages (emitted once) ──────────────────────────────────────
		if (!this.headerSent) {
			pages.push(
				buildOggPage({
					headerType: 0x02, // BOS
					granulePos: 0,
					serialNo: this.serialNo,
					pageSeq: this.pageSeq++,
					payload: buildOpusHead(this.channels, this.sampleRate, 3840),
				})
			)
			this.headerSent = true
		}

		if (!this.tagsSent) {
			pages.push(
				buildOggPage({
					headerType: 0x00,
					granulePos: 0,
					serialNo: this.serialNo,
					pageSeq: this.pageSeq++,
					payload: buildOpusTags(),
				})
			)
			this.tagsSent = true
		}

		// ── Encode audio in 80 ms frames (matching sphn exactly) ────────────
		let offset = 0

		while (offset + this.frameSamples <= pcmFloat32.length) {
			const framePcm = pcmFloat32.subarray(offset, offset + this.frameSamples)
			offset += this.frameSamples

			// Convert float32 [-1, 1] → int16 (opusscript expects Int16 PCM)
			const int16 = new Int16Array(framePcm.length)
			for (let i = 0; i < framePcm.length; i++) {
				const s = Math.max(-1, Math.min(1, framePcm[i]))
				int16[i] = s < 0 ? s * 0x8000 : s * 0x7fff
			}

			const encoded: Uint8Array = this.encoder.encode(
				Buffer.from(int16.buffer),
				this.frameSamples
			)

			this.granulePos += this.frameSamples

			// One Opus packet per OGG page (same structure as sphn)
			pages.push(
				buildOggPage({
					headerType: 0x00,
					granulePos: this.granulePos,
					serialNo: this.serialNo,
					pageSeq: this.pageSeq++,
					payload: new Uint8Array(encoded),
				})
			)
		}

		// Concatenate all pages
		const totalBytes = pages.reduce((s, p) => s + p.length, 0)
		const result = new Uint8Array(totalBytes)
		let rOff = 0
		for (const p of pages) {
			result.set(p, rOff)
			rOff += p.length
		}
		return result
	}

	destroy(): void {
		this.encoder.delete()
	}
}

// ── OGG page with explicit per-frame segments ────────────────────────────────

/**
 * Build an OGG page where each entry in `segments` is a separate Opus packet.
 * The segment table reflects the individual packet boundaries so that the
 * decoder can recover each Opus frame.
 */
// @ts-expect-error unused
function buildOggPageMultiSegment(opts: {
	headerType: number
	granulePos: number
	serialNo: number
	pageSeq: number
	segments: Uint8Array[]
}): Uint8Array {
	const { headerType, granulePos, serialNo, pageSeq, segments } = opts

	// Build segment table: for each Opus packet, emit 255s + remainder
	const segTable: number[] = []
	for (const pkt of segments) {
		let rem = pkt.length
		while (rem >= 255) {
			segTable.push(255)
			rem -= 255
		}
		segTable.push(rem)
	}

	// Total payload
	const payloadLen = segments.reduce((s, p) => s + p.length, 0)
	const headerSize = 27 + segTable.length
	const page = new Uint8Array(headerSize + payloadLen)

	page.set(OGG_CAPTURE, 0)
	page[4] = 0
	page[5] = headerType
	writeGranuleLE(page, 6, granulePos)
	writeU32LE(page, 14, serialNo)
	writeU32LE(page, 18, pageSeq)
	writeU32LE(page, 22, 0) // CRC placeholder
	page[26] = segTable.length
	for (let i = 0; i < segTable.length; i++) {
		page[27 + i] = segTable[i]
	}

	let off = headerSize
	for (const pkt of segments) {
		page.set(pkt, off)
		off += pkt.length
	}

	const crc = oggCrc32(page)
	writeU32LE(page, 22, crc)

	return page
}

// ── OGG Opus stream reader (for playback) ────────────────────────────────────

/**
 * Streaming OGG Opus decoder.
 *
 * Mirrors `sphn.OpusStreamReader`: accepts arbitrary chunks of OGG Opus
 * bytes and returns decoded PCM float32 samples.
 */
export class OggOpusReader {
	private decoder: InstanceType<typeof OpusScript>
	private buf = new Uint8Array(0)
	private headerParsed = false
	private tagsParsed = false

	constructor(sampleRate: number, channels = 1) {
		this.decoder = new OpusScript(
			sampleRate as 8000 | 12000 | 16000 | 24000 | 48000,
			channels,
			OpusScript.Application.VOIP,
			(_wasmBinary ? { wasm: true, wasmBinary: _wasmBinary } : { wasm: false }) as any,
		)
	}

	/**
	 * Feed OGG Opus bytes and get back decoded PCM float32 samples.
	 * Returns an empty array if no complete pages are available yet.
	 */
	decode(data: Uint8Array): Float32Array[] {
		// Append incoming data to internal buffer
		const combined = new Uint8Array(this.buf.length + data.length)
		combined.set(this.buf)
		combined.set(data, this.buf.length)
		this.buf = combined

		const pcmChunks: Float32Array[] = []

		// Parse as many complete OGG pages as possible
		while (true) {
			const page = this.tryParsePage()
			if (!page) break

			// First two pages are OpusHead and OpusTags — skip them
			if (!this.headerParsed) {
				this.headerParsed = true
				continue
			}
			if (!this.tagsParsed) {
				this.tagsParsed = true
				continue
			}

			// Decode each Opus packet in the data page
			for (const packet of page.packets) {
				try {
					const decoded: Uint8Array = this.decoder.decode(Buffer.from(packet))
					// opusscript returns Int16 PCM in its emscripten heap.
					// Copy to a fresh aligned buffer — the heap view may have an
					// odd byteOffset which would crash the Int16Array constructor.
					const aligned = new Uint8Array(decoded.length)
					aligned.set(decoded)
					const int16 = new Int16Array(aligned.buffer)
					const float32 = new Float32Array(int16.length)
					for (let i = 0; i < int16.length; i++) {
						float32[i] = int16[i] / 32768
					}
					pcmChunks.push(float32)
				} catch (e) {
					console.warn('[OggOpusReader] packet decode error:', e)
				}
			}
		}

		return pcmChunks
	}

	/** Try to parse one complete OGG page from the front of `this.buf`. */
	private tryParsePage(): { packets: Uint8Array[] } | null {
		if (this.buf.length < 27) return null

		// Verify capture pattern "OggS"
		if (
			this.buf[0] !== 0x4f ||
			this.buf[1] !== 0x67 ||
			this.buf[2] !== 0x67 ||
			this.buf[3] !== 0x53
		) {
			// Scan forward for the next "OggS" sync
			let found = -1
			for (let i = 1; i <= this.buf.length - 4; i++) {
				if (
					this.buf[i] === 0x4f &&
					this.buf[i + 1] === 0x67 &&
					this.buf[i + 2] === 0x67 &&
					this.buf[i + 3] === 0x53
				) {
					found = i
					break
				}
			}
			if (found === -1) {
				this.buf = this.buf.slice(Math.max(0, this.buf.length - 3))
				return null
			}
			this.buf = this.buf.slice(found)
			if (this.buf.length < 27) return null
		}

		const numSegments = this.buf[26]
		const headerSize = 27 + numSegments
		if (this.buf.length < headerSize) return null

		let payloadSize = 0
		for (let i = 0; i < numSegments; i++) {
			payloadSize += this.buf[27 + i]
		}

		const totalPageSize = headerSize + payloadSize
		if (this.buf.length < totalPageSize) return null

		// Extract packets from segment table
		const packets: Uint8Array[] = []
		let currentParts: Uint8Array[] = []
		let payloadOffset = headerSize

		for (let i = 0; i < numSegments; i++) {
			const segSize = this.buf[27 + i]
			if (segSize > 0) {
				currentParts.push(this.buf.slice(payloadOffset, payloadOffset + segSize))
			}
			payloadOffset += segSize

			if (segSize < 255) {
				// Packet boundary
				const totalLen = currentParts.reduce((s, c) => s + c.length, 0)
				if (totalLen > 0) {
					const pkt = new Uint8Array(totalLen)
					let off = 0
					for (const part of currentParts) {
						pkt.set(part, off)
						off += part.length
					}
					packets.push(pkt)
				}
				currentParts = []
			}
		}
		// Trailing continued packet (last segment was 255)
		if (currentParts.length > 0) {
			const totalLen = currentParts.reduce((s, c) => s + c.length, 0)
			if (totalLen > 0) {
				const pkt = new Uint8Array(totalLen)
				let off = 0
				for (const part of currentParts) {
					pkt.set(part, off)
					off += part.length
				}
				packets.push(pkt)
			}
		}

		// Consume this page
		this.buf = this.buf.slice(totalPageSize)
		return { packets }
	}

	destroy(): void {
		this.decoder.delete()
	}
}
